import React, { useState, useEffect } from "react";
import api from "../../api";
import "../../App.css";

import FullCalendar from "@fullcalendar/react";
import dayGridPlugin from "@fullcalendar/daygrid";
import timeGridPlugin from "@fullcalendar/timegrid";
import interactionPlugin from "@fullcalendar/interaction";

export default function Schedule({ user }) {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);

  const fmt = (d) => d.toISOString().split("T")[0];

  useEffect(() => {
    const fetchShifts = async () => {
      setLoading(true);
      try {
        // You can adjust range if needed
        const today = new Date();
        const start = fmt(new Date(today.getFullYear(), today.getMonth(), 1));
        const end = fmt(new Date(today.getFullYear(), today.getMonth() + 1, 0));

        const res = await api.get(`/shifts/week?start=${start}&end=${end}`);
        const shifts = res.data.shifts || [];

        const mapped = shifts.map((shift) => ({
          id: shift._id,
          title: `${shift.role}${shift.area ? ` (${shift.area})` : ""}`,
          start: `${shift.date}T${shift.startTime}`,
          end: `${shift.date}T${shift.endTime}`
        }));

        setEvents(mapped);
      } catch (err) {
        console.error("Failed to load shifts:", err);

        const fallback = [
          { _id: "1", date: fmt(new Date()), startTime: "09:00", endTime: "17:00", role: "Waitstaff", area: "Front" }
        ];

        setEvents(
          fallback.map((shift) => ({
            id: shift._id,
            title: `${shift.role} (${shift.area})`,
            start: `${shift.date}T${shift.startTime}`,
            end: `${shift.date}T${shift.endTime}`
          }))
        );
      } finally {
        setLoading(false);
      }
    };

    fetchShifts();
  }, []);

  return (
    <div className="su-page">

      {/* TITLE */}
      <div className="su-title mb-4">MY SCHEDULE</div>

      {/* PROFILE CARD */}
      <div className="su-card mb-4" style={{ maxWidth: 300 }}>
        <div className="su-card-title">My Profile</div>
        <div className="text-sm"><strong>Name:</strong> {user?.name || `${user?.firstName} ${user?.lastName}`}</div>
        <div className="text-sm mt-2"><strong>Role:</strong> {user?.position || user?.role}</div>
        <div className="text-sm mt-2"><strong>Availability:</strong> {user?.availability}</div>
        <div className="text-sm mt-2"><strong>Email:</strong> {user?.email}</div>
      </div>

      {/* CALENDAR */}
      {loading ? (
        <div style={{ padding: 40 }}>Loading shifts...</div>
      ) : (
        <main className="schedule">
          <FullCalendar
            plugins={[dayGridPlugin, timeGridPlugin, interactionPlugin]}
            initialView="timeGridWeek"
            headerToolbar={{
              left: "prev,next today",
              center: "title",
              right: "dayGridMonth,timeGridWeek,timeGridDay"
            }}
            events={events}
            height="auto"
          />
        </main>
      )}

    </div>
  );
}
